'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { dashboardApi, DepotCapacity } from '@/lib/api';

interface DepotCardProps {
  depot: DepotCapacity;
  onClick?: () => void;
}

/**
 * Individual Depot Card Component
 */
function DepotCard({ depot, onClick }: DepotCardProps) {
  // Determine color based on usage percentage
  const getUsageColor = (percent: number) => {
    if (percent < 70) return 'bg-status-available';
    if (percent < 90) return 'bg-variance-yellow';
    return 'bg-status-maintenance';
  };

  const getTextColor = (percent: number) => {
    if (percent < 70) return 'text-status-available';
    if (percent < 90) return 'text-variance-yellow';
    return 'text-status-maintenance';
  };

  return (
    <div
      className="bg-panel rounded-lg p-4 hover:bg-elevated transition-all duration-200 cursor-pointer border border-border"
      onClick={onClick}
      role="button"
      tabIndex={0}
    >
      <div className="flex justify-between items-start mb-3">
        <div>
          <h3 className="font-semibold text-text-primary">{depot.name}</h3>
          <span className="text-xs text-text-muted font-mono">{depot.code}</span>
        </div>
        <span className={`text-lg font-bold ${getTextColor(depot.percentUsed)}`}>
          {depot.percentUsed}%
        </span>
      </div>

      {/* Capacity Bar */}
      <div className="mb-2">
        <div className="flex justify-between text-xs text-text-muted mb-1">
          <span>Tracks</span>
          <span>{depot.currentOccupancy}/{depot.maxCapacity}</span>
        </div>
        <div className="w-full bg-elevated rounded-full h-2.5">
          <div
            className={`h-2.5 rounded-full transition-all duration-300 ${getUsageColor(depot.percentUsed)}`}
            style={{ width: `${Math.min(depot.percentUsed, 100)}%` }}
          />
        </div>
      </div>

      {/* Status Indicator */}
      <div className="flex items-center text-xs">
        {depot.percentUsed >= 90 && (
          <span className="text-status-maintenance">
            Capacity critical
          </span>
        )}
        {depot.percentUsed >= 70 && depot.percentUsed < 90 && (
          <span className="text-variance-yellow">
            High usage
          </span>
        )}
        {depot.percentUsed < 70 && (
          <span className="text-status-available">
            Capacity available
          </span>
        )}
      </div>
    </div>
  );
}

/**
 * Depot Capacity Cards Component
 *
 * Displays depot occupancy grid showing current vs max capacity
 * with color-coded indicators.
 */
export function DepotCapacityCards() {
  const router = useRouter();
  const [depots, setDepots] = useState<DepotCapacity[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchDepots() {
      setLoading(true);
      const { data, error } = await dashboardApi.getDepotCapacity();

      if (error) {
        setError(error);
      } else if (data) {
        // Sort by usage percentage (highest first)
        const sorted = [...data.depots].sort((a, b) => b.percentUsed - a.percentUsed);
        setDepots(sorted);
      }
      setLoading(false);
    }

    fetchDepots();
  }, []);

  const handleDepotClick = (depotId: string) => {
    router.push(`/fleet?depot=${depotId}`);
  };

  if (loading) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {[...Array(8)].map((_, i) => (
          <div key={i} className="bg-panel rounded-lg p-4 animate-pulse border border-border">
            <div className="h-5 bg-elevated rounded w-2/3 mb-2"></div>
            <div className="h-3 bg-elevated rounded w-1/4 mb-4"></div>
            <div className="h-2.5 bg-elevated rounded-full w-full"></div>
          </div>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-900/20 border border-red-800 rounded-lg p-4">
        <p className="text-red-400">
          <strong>Error loading depot capacity:</strong> {error}
        </p>
      </div>
    );
  }

  if (depots.length === 0) {
    return (
      <div className="bg-panel border border-border rounded-lg p-8 text-center text-text-muted">
        No depot data available
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
      {depots.map((depot) => (
        <DepotCard
          key={depot.id}
          depot={depot}
          onClick={() => handleDepotClick(depot.id)}
        />
      ))}
    </div>
  );
}

